{"path": "/tmp/sv-6b51361a145b4457a8494c962c81c842/Components/Catalog/CatalogFilters.razor", "file_text": "@using sv_6b51361a145b4457a8494c962c81c842.Services

<div class="catalog-filters">
    <h5>Filters</h5>

    <div class="filter-section">
        <h6>Category</h6>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                       checked="@IsSelected(category)"
                       @onchange="@(e => ToggleCategory(category, (bool)(e.Value ?? false)))" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="filter-section">
        <h6>Price Range</h6>
        <div class="mb-2">
            <label class="form-label form-label-sm">Min Price</label>
            <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                   @bind="minPrice" placeholder="Min" />
        </div>
        <div class="mb-2">
            <label class="form-label form-label-sm">Max Price</label>
            <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                   @bind="maxPrice" placeholder="Max" />
        </div>
    </div>

    <div class="filter-section">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   @bind="inStockOnly" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="filter-actions">
        <button class="btn btn-primary btn-sm w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm w-100" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    private List<string> selectedCategories = [];
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private bool IsSelected(string category) => selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked && !selectedCategories.Contains(category))
        {
            selectedCategories.Add(category);
        }
        else if (!isChecked)
        {
            selectedCategories.Remove(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? new List<string>(selectedCategories) : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFiltersApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }
}
"}

