@using sv_6b51361a145b4457a8494c962c81c842.Services

<div class="product-card" @onclick="HandleCardClick">
    <div class="product-image" title="@Product.Name">
        @Product.Name
    </div>
    <div class="product-info">
        <h5 class="product-name">@Product.Name</h5>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" title="@($"{Product.Rating:F1} out of 5")">
            @GetStarDisplay(Product.Rating)
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger">Out of Stock</span>
        }
        <button class="btn btn-primary btn-sm mt-2"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarDisplay(double rating)
    {
        int filled = (int)Math.Round(rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }
}

