    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    private List<string> selectedCategories = [];
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private bool IsSelected(string category) => selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked && !selectedCategories.Contains(category))
        {
            selectedCategories.Add(category);
        }
        else if (!isChecked)
        {
            selectedCategories.Remove(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? new List<string>(selectedCategories) : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFiltersApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }
}

