+<nav aria-label="Product catalog pagination">
+    <ul class="pagination justify-content-center">
+        <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
+            <button class="page-link" @onclick="@(() => GoToPage(CurrentPage - 1))" disabled="@(CurrentPage <= 1)">
+                Previous
+            </button>
+        </li>
+        @foreach (var page in GetPageNumbers())
+        {
+            <li class="page-item @(page == CurrentPage ? "active" : "")">
+                <button class="page-link" @onclick="@(() => GoToPage(page))">@page</button>
+            </li>
+        }
+        <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
+            <button class="page-link" @onclick="@(() => GoToPage(CurrentPage + 1))" disabled="@(CurrentPage >= TotalPages)">
+                Next
+            </button>
+        </li>
+    </ul>
+</nav>
+
+@code {
+    [Parameter]
+    public int CurrentPage { get; set; } = 1;
+
+    [Parameter]
+    public int TotalPages { get; set; } = 1;
+
+    [Parameter]
+    public EventCallback<int> OnPageChanged { get; set; }
+
+    private async Task GoToPage(int page)
+    {
+        if (page >= 1 && page <= TotalPages && page != CurrentPage)
+        {
+            await OnPageChanged.InvokeAsync(page);
+        }
+    }
+
+    private IEnumerable<int> GetPageNumbers()
+    {
+        const int maxVisible = 5;
+
+        if (TotalPages <= maxVisible)
+        {
+            return Enumerable.Range(1, TotalPages);
+        }
+
+        int start = Math.Max(1, CurrentPage - maxVisible / 2);
+        int end = Math.Min(TotalPages, start + maxVisible - 1);
+
+        if (end - start + 1 < maxVisible)
+        {
+            start = Math.Max(1, end - maxVisible + 1);
+        }
+
+        return Enumerable.Range(start, end - start + 1);
+    }
+}
+

